    private inner class ServiceHandler(looper: Looper) : Handler(looper) {
        override fun handleMessage(msg: Message) {
            val intent = msg.obj as? Intent
            val startId = msg.arg1
            val taskId = msg.arg2

            if (intent == null) {
                stopSelfResult(startId)
                return
            }

            val taskType = intent.getStringExtra(TASK_TYPE_KEY) ?: TASK_FULL_MAINTENANCE
            val callbackAction = intent.getStringExtra(PARAM_CALLBACK_ACTION)
            val callbackPackage = intent.getStringExtra(PARAM_CALLBACK_PACKAGE)

            val taskInfo = TaskInfo(
                taskId = taskId,
                taskType = taskType,
                startTime = System.currentTimeMillis(),
                callbackAction = callbackAction,
                callbackPackage = callbackPackage
            )
            activeTasks[taskId] = taskInfo

            Log.i(TAG, "Processing task #$taskId: $taskType")
            updateNotification("Processing: $taskType (Task #$taskId)")

            val result = try {
                when (taskType) {
                    TASK_DATA_SYNC -> performDataSync(taskId, intent)
                    TASK_CACHE_CLEANUP -> performCacheCleanup(taskId, intent)
                    TASK_LOG_CLEANUP -> performLogCleanup(taskId, intent)
                    TASK_DATABASE_OPTIMIZE -> performDatabaseOptimize(taskId, intent)
                    TASK_TEMP_FILE_CLEANUP -> performTempFileCleanup(taskId, intent)
                    TASK_FULL_MAINTENANCE -> performFullMaintenance(taskId, intent)
                    else -> TaskResult(
                        taskId = taskId,
                        status = STATUS_FAILURE,
                        message = "Unknown task type: $taskType"
                    )
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error processing task #$taskId", e)
                TaskResult(
                    taskId = taskId,
                    status = STATUS_FAILURE,
                    message = "Error: ${e.message}",
                    durationMs = System.currentTimeMillis() - taskInfo.startTime
                )
            }

            sendResultCallback(taskInfo, result)
            activeTasks.remove(taskId)

            Log.i(TAG, "Task #$taskId completed: ${result.status} - ${result.message}")

            if (activeTasks.isEmpty()) {
                updateNotification("All tasks completed")
                stopSelfResult(startId)
            }
        }
    }

