    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.i(TAG, "Received start command, startId=$startId")

        if (intent == null) {
            Log.w(TAG, "Received null intent, stopping")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val taskType = intent.getStringExtra(TASK_TYPE_KEY)
        if (taskType == null) {
            Log.w(TAG, "No task type specified, stopping")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        // Validate calling package permissions
        val callingPackage = intent.getStringExtra("calling_package") ?: "unknown"
        Log.i(TAG, "Task requested by: $callingPackage, type: $taskType")

        val taskId = taskCounter.incrementAndGet()

        val msg = serviceHandler.obtainMessage().apply {
            arg1 = startId
            arg2 = taskId
            obj = intent
        }
        serviceHandler.sendMessage(msg)

        return START_REDELIVER_INTENT
    }

    override fun onBind(intent: Intent?): IBinder? {
        return null
