    private fun performDataSync(taskId: Int, intent: Intent): TaskResult {
        val startTime = System.currentTimeMillis()
        val syncUrl = intent.getStringExtra(PARAM_SYNC_URL) ?: "default"
        val syncToken = intent.getStringExtra(PARAM_SYNC_TOKEN)
        val syncDataType = intent.getStringExtra(PARAM_SYNC_DATA_TYPE) ?: "all"

        Log.i(TAG, "Task #$taskId: Data sync started - url=$syncUrl, dataType=$syncDataType")

        var itemsSynced = 0

        try {
            // Simulate syncing different data types
            val dataTypes = if (syncDataType == "all") {
                listOf("settings", "preferences", "usage_stats", "app_data")
            } else {
                syncDataType.split(",")
            }

            for (dataType in dataTypes) {
                Log.d(TAG, "Task #$taskId: Syncing $dataType...")

                // Simulate sync work
                val syncFile = File(filesDir, "sync_${dataType}.json")
                val syncData = collectSyncData(dataType)
                syncFile.writeText(syncData)

                // Simulate network delay
                Thread.sleep(500)

                // Mark as synced
                val prefs = getSharedPreferences("sync_status", MODE_PRIVATE)
                prefs.edit()
                    .putLong("last_sync_${dataType}", System.currentTimeMillis())
                    .putString("sync_status_${dataType}", "completed")
                    .apply()

                itemsSynced++
                Log.d(TAG, "Task #$taskId: Synced $dataType successfully")
            }

            val duration = System.currentTimeMillis() - startTime
            return TaskResult(
                taskId = taskId,
                status = STATUS_SUCCESS,
                message = "Synced $itemsSynced data types successfully",
                itemsProcessed = itemsSynced,
                durationMs = duration
            )
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            return TaskResult(
                taskId = taskId,
                status = if (itemsSynced > 0) STATUS_PARTIAL else STATUS_FAILURE,
                message = "Sync error after $itemsSynced items: ${e.message}",
                itemsProcessed = itemsSynced,
                durationMs = duration
            )
        }
    }

