    private fun performDatabaseOptimize(taskId: Int, intent: Intent): TaskResult {
        val startTime = System.currentTimeMillis()
        val shouldVacuum = intent.getBooleanExtra(PARAM_DB_VACUUM, true)
        val shouldReindex = intent.getBooleanExtra(PARAM_DB_REINDEX, true)

        Log.i(TAG, "Task #$taskId: Database optimize started - vacuum=$shouldVacuum, reindex=$shouldReindex")

        var operationsCompleted = 0
        var bytesFreed = 0L

        try {
            val dbDir = getDatabasePath("dummy").parentFile
            if (dbDir != null && dbDir.exists()) {
                val dbFiles = dbDir.listFiles { file ->
                    file.name.endsWith(".db") || file.name.endsWith(".sqlite")
                } ?: emptyArray()

                for (dbFile in dbFiles) {
                    try {
                        val sizeBefore = dbFile.length()

                        val db = android.database.sqlite.SQLiteDatabase.openDatabase(
                            dbFile.absolutePath,
                            null,
                            android.database.sqlite.SQLiteDatabase.OPEN_READWRITE
                        )

                        if (shouldVacuum) {
                            Log.d(TAG, "Task #$taskId: VACUUM on ${dbFile.name}")
                            db.execSQL("VACUUM")
                            operationsCompleted++
                        }

                        if (shouldReindex) {
                            Log.d(TAG, "Task #$taskId: REINDEX on ${dbFile.name}")
                            db.execSQL("REINDEX")
                            operationsCompleted++
                        }

                        // Analyze for query optimization
                        db.execSQL("ANALYZE")
                        operationsCompleted++

                        db.close()

                        val sizeAfter = dbFile.length()
                        if (sizeBefore > sizeAfter) {
                            bytesFreed += (sizeBefore - sizeAfter)
                        }
                    } catch (e: Exception) {
                        Log.w(TAG, "Task #$taskId: Error optimizing ${dbFile.name}: ${e.message}")
                    }
                }
            }

            // Clean WAL and journal files
            dbDir?.listFiles { file ->
                file.name.endsWith("-wal") || file.name.endsWith("-journal") || file.name.endsWith("-shm")
            }?.forEach { file ->
                val size = file.length()
                if (file.delete()) {
                    bytesFreed += size
                    operationsCompleted++
                }
            }

            val duration = System.currentTimeMillis() - startTime
            return TaskResult(
                taskId = taskId,
                status = STATUS_SUCCESS,
                message = "Database optimize: $operationsCompleted operations, freed ${formatBytes(bytesFreed)}",
                itemsProcessed = operationsCompleted,
                bytesFreed = bytesFreed,
                durationMs = duration
            )
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            return TaskResult(
                taskId = taskId,
                status = if (operationsCompleted > 0) STATUS_PARTIAL else STATUS_FAILURE,
                message = "Database optimize error: ${e.message}",
                itemsProcessed = operationsCompleted,
                bytesFreed = bytesFreed,
                durationMs = duration
            )
        }
    }

    private fun performTempFileCleanup(taskId: Int, intent: Intent): TaskResult {
        val startTime = System.currentTimeMillis()
        val targetDir = intent.getStringExtra(PARAM_CLEANUP_TARGET_DIR)
        val maxAgeDays = intent.getIntExtra(PARAM_CLEANUP_MAX_AGE_DAYS, 1)

        Log.i(TAG, "Task #$taskId: Temp file cleanup started - targetDir=$targetDir, maxAge=${maxAgeDays}d")

        var filesDeleted = 0
        var bytesFreed = 0L
        val cutoffTime = System.currentTimeMillis() - (maxAgeDays * 24 * 60 * 60 * 1000L)

        try {
            // Clean app's temp directories
            val tempDirs = mutableListOf<File>()

            if (targetDir != null) {
                val dir = File(filesDir, targetDir)
                if (dir.exists()) tempDirs.add(dir)
            } else {
                // Default temp directories
                tempDirs.add(File(filesDir, "temp"))
                tempDirs.add(File(filesDir, "tmp"))
                tempDirs.add(File(cacheDir, "temp"))
                externalCacheDir?.let { tempDirs.add(File(it, "temp")) }
            }

            for (dir in tempDirs) {
                if (dir.exists() && dir.isDirectory) {
                    val result = cleanDirectory(dir, cutoffTime, Long.MAX_VALUE)
                    filesDeleted += result.first
                    bytesFreed += result.second
                }
            }

            // Clean .tmp files in files directory
            filesDir.listFiles { file -> file.name.endsWith(".tmp") }?.forEach { file ->
                if (file.lastModified() < cutoffTime) {
                    val size = file.length()
                    if (file.delete()) {
                        filesDeleted++
                        bytesFreed += size
                    }
                }
            }

            val duration = System.currentTimeMillis() - startTime
            return TaskResult(
                taskId = taskId,
                status = STATUS_SUCCESS,
                message = "Temp cleanup: deleted $filesDeleted files, freed ${formatBytes(bytesFreed)}",
                itemsProcessed = filesDeleted,
                bytesFreed = bytesFreed,
                durationMs = duration
            )
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            return TaskResult(
                taskId = taskId,
                status = if (filesDeleted > 0) STATUS_PARTIAL else STATUS_FAILURE,
                message = "Temp cleanup error: ${e.message}",
                itemsProcessed = filesDeleted,
                bytesFreed = bytesFreed,
                durationMs = duration
            )
        }
    }

    private fun performFullMaintenance(taskId: Int, intent: Intent): TaskResult {
        val startTime = System.currentTimeMillis()
        Log.i(TAG, "Task #$taskId: Full maintenance started")

        var totalItemsProcessed = 0
        var totalBytesFreed = 0L
        val results = mutableListOf<String>()

        // 1. Cache cleanup
        try {
            val cacheResult = performCacheCleanup(taskId, Intent().apply {
                putExtra(PARAM_CLEANUP_MAX_AGE_DAYS, 3)
                putExtra(PARAM_CLEANUP_MAX_SIZE_MB, 50)
            })
            totalItemsProcessed += cacheResult.itemsProcessed
            totalBytesFreed += cacheResult.bytesFreed
            results.add("Cache: ${cacheResult.status}")
        } catch (e: Exception) {
            results.add("Cache: failed")
        }

        // 2. Temp file cleanup
        try {
            val tempResult = performTempFileCleanup(taskId, Intent().apply {
                putExtra(PARAM_CLEANUP_MAX_AGE_DAYS, 1)
            })
            totalItemsProcessed += tempResult.itemsProcessed
            totalBytesFreed += tempResult.bytesFreed
            results.add("Temp: ${tempResult.status}")
        } catch (e: Exception) {
            results.add("Temp: failed")
        }

        // 3. Log cleanup
        try {
            val logResult = performLogCleanup(taskId, Intent().apply {
                putExtra(PARAM_CLEANUP_MAX_AGE_DAYS, 14)
            })
            totalItemsProcessed += logResult.itemsProcessed
            totalBytesFreed += logResult.bytesFreed
            results.add("Logs: ${logResult.status}")
        } catch (e: Exception) {
            results.add("Logs: failed")
        }

        // 4. Database optimize
        try {
            val dbResult = performDatabaseOptimize(taskId, Intent().apply {
                putExtra(PARAM_DB_VACUUM, true)
                putExtra(PARAM_DB_REINDEX, false)
            })
            totalItemsProcessed += dbResult.itemsProcessed
            totalBytesFreed += dbResult.bytesFreed
            results.add("DB: ${dbResult.status}")
        } catch (e: Exception) {
            results.add("DB: failed")
        }

        // 5. Data sync
        try {
            val syncResult = performDataSync(taskId, Intent().apply {
                putExtra(PARAM_SYNC_DATA_TYPE, "settings,preferences")
            })
            totalItemsProcessed += syncResult.itemsProcessed
            results.add("Sync: ${syncResult.status}")
        } catch (e: Exception) {
            results.add("Sync: failed")
        }

        // Record maintenance completion
        val prefs = getSharedPreferences("maintenance_history", MODE_PRIVATE)
        val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault())
        prefs.edit()
            .putString("last_full_maintenance", dateFormat.format(Date()))
            .putInt("last_items_processed", totalItemsProcessed)
            .putLong("last_bytes_freed", totalBytesFreed)
            .apply()

        val hasFailures = results.any { it.contains("failed") }
        val duration = System.currentTimeMillis() - startTime

        return TaskResult(
            taskId = taskId,
            status = if (hasFailures) STATUS_PARTIAL else STATUS_SUCCESS,
            message = "Full maintenance: ${results.joinToString(", ")}. " +
                    "Total freed: ${formatBytes(totalBytesFreed)}",
            itemsProcessed = totalItemsProcessed,
            bytesFreed = totalBytesFreed,
            durationMs = duration
        )
    }

    // --- Helper Methods ---

    private fun cleanDirectory(directory: File, cutoffTime: Long, maxTotalSize: Long): Pair<Int, Long> {
        var filesDeleted = 0
        var bytesFreed = 0L

        if (!directory.exists() || !directory.isDirectory) return Pair(0, 0L)

        val files = directory.listFiles() ?: return Pair(0, 0L)

        // First pass: delete old files
        for (file in files) {
            if (file.isDirectory) {
                val subResult = cleanDirectory(file, cutoffTime, Long.MAX_VALUE)
                filesDeleted += subResult.first
                bytesFreed += subResult.second

                // Remove empty directories
                if (file.listFiles()?.isEmpty() == true) {
                    file.delete()
                }
            } else if (file.lastModified() < cutoffTime) {
                val size = file.length()
                if (file.delete()) {
                    filesDeleted++
                    bytesFreed += size
                }
            }
        }

        // Second pass: if still over size limit, delete largest files first
        if (maxTotalSize < Long.MAX_VALUE) {
            val remainingFiles = directory.listFiles()?.filter { it.isFile }
                ?.sortedByDescending { it.length() } ?: emptyList()

            var currentSize = remainingFiles.sumOf { it.length() }

            for (file in remainingFiles) {
                if (currentSize <= maxTotalSize) break
                val size = file.length()
                if (file.delete()) {
                    filesDeleted++
                    bytesFreed += size
                    currentSize -= size
                }
            }
        }

        return Pair(filesDeleted, bytesFreed)
    }

    private fun collectSyncData(dataType: String): String {
        val timestamp = SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'", Locale.getDefault()).format(Date())

        return when (dataType) {
            "settings" -> {
                val prefs = getSharedPreferences("app_settings", MODE_PRIVATE)
                val allEntries = prefs.all
                buildString {
                    append("{\"type\":\"settings\",\"timestamp\":\"$timestamp\",\"data\":{")
                    append(allEntries.entries.joinToString(",") { "\"${it.key}\":\"${it.value}\"" })
                    append("}}")
                }
            }
            "preferences" -> {
                val prefs = getSharedPreferences("user_preferences", MODE_PRIVATE)
                val allEntries = prefs.all
                buildString {
                    append("{\"type\":\"preferences\",\"timestamp\":\"$timestamp\",\"data\":{")
                    append(allEntries.entries.joinToString(",") { "\"${it.key}\":\"${it.value}\"" })
                    append("}}")
                }
            }
            "usage_stats" -> {
                "{\"type\":\"usage_stats\",\"timestamp\":\"$timestamp\",\"data\":{\"sessions\":0}}"
            }
            "app_data" -> {
                "{\"type\":\"app_data\",\"timestamp\":\"$timestamp\",\"data\":{}}"
            }
            else -> {
                "{\"type\":\"$dataType\",\"timestamp\":\"$timestamp\",\"data\":{}}"
            }
        }
    }

    private fun sendResultCallback(taskInfo: TaskInfo, result: TaskResult) {
        val callbackAction = taskInfo.callbackAction
        val callbackPackage = taskInfo.callbackPackage

        if (callbackAction != null && callbackPackage != null) {
            try {
                val callbackIntent = Intent(callbackAction).apply {
                    setPackage(callbackPackage)
                    putExtra(RESULT_TASK_ID, result.taskId)
                    putExtra(RESULT_STATUS, result.status)
                    putExtra(RESULT_MESSAGE, result.message)
                    putExtra(RESULT_ITEMS_PROCESSED, result.itemsProcessed)
                    putExtra(RESULT_BYTES_FREED, result.bytesFreed)
                    putExtra(RESULT_DURATION_MS, result.durationMs)
                    addFlags(Intent.FLAG_INCLUDE_STOPPED_PACKAGES)
                }
                sendBroadcast(callbackIntent)
                Log.i(TAG, "Sent callback to $callbackPackage/$callbackAction for task #${result.taskId}")
            } catch (e: Exception) {
                Log.e(TAG, "Failed to send callback: ${e.message}")
            }
        }
    }

    private fun formatBytes(bytes: Long): String {
        return when {
            bytes >= 1024 * 1024 * 1024 -> "%.2f GB".format(bytes / (1024.0 * 1024.0 * 1024.0))
            bytes >= 1024 * 1024 -> "%.2f MB".format(bytes / (1024.0 * 1024.0))
            bytes >= 1024 -> "%.2f KB".format(bytes / 1024.0)
            else -> "$bytes B"
        }
    }

